local function load_from_redis(redis_host, redis_port, plugin_key)
    local red = redis:new()
    red:set_timeout(1000)
    
    local ok, err = red:connect(redis_host, redis_port)
    if not ok then
        return nil, "Failed to connect to Redis: " .. err
    end
    
    local code, err = red:get(plugin_key)
    if not code or code == ngx.null then
        red:set_keepalive(10000, 100)
        return nil, "Plugin not found in Redis"
    end
    
    red:set_keepalive(10000, 100)
    return code
end

